#!/usr/bin/env python3
# writer.py — Piece M2: the single-agent Manager loop.
# 1) Creates src/agent/managerLoop.js (runManagerTurn).
# 2) Makes the firewall mode-aware (don't scrub the face) + manager beat cases.
# 3) Routes chat.js by per-turn mode (default = manager -> runManagerTurn).
# Guarded + idempotent: each edit fires only when its exact anchor is present once and
# its guard string is absent. myraLoop.js, kriyaTurn.js, KRIYA_SOUL are NEVER touched.
# Depends on M1 (kriyaManagerSoul) being applied first.
import base64, os, sys

ML_B64 = """"""

NEW_FILE = os.path.join("src", "agent", "managerLoop.js")

EDITS = [
    {'file': 'src/agent/displayFirewall.js', 'anchor_b64': 'ICBmb3IgKGNvbnN0IFtyZSwgcmVwXSBvZiBTQ1JVQlMpIG91dCA9IG91dC5yZXBsYWNlKHJlLCByZXApOwogIHJldHVybiBvdXQ7Cn0=', 'repl_b64': '', 'guard': 'scrubToolsOnly'},
    {'file': 'src/agent/displayFirewall.js', 'anchor_b64': 'ZnVuY3Rpb24gdHJhbnNsYXRlQmVhdChlKSB7CiAgaWYgKCFlIHx8ICFlLnR5cGUpIHJldHVybiBudWxsOw==', 'repl_b64': '', 'guard': 'function translateBeat(e, mode)'},
    {'file': 'src/agent/displayFirewall.js', 'anchor_b64': '', 'repl_b64': '', 'guard': "case 'manager_token':"},
    {'file': 'src/agent/displayFirewall.js', 'anchor_b64': 'ICAgIGNhc2UgJ2Fuc3dlcic6CiAgICAgIHJldHVybiB7IHR5cGU6ICdhbnN3ZXInLCByZXBseTogc2NydWIoZS5yZXBseSkgfTs=', 'repl_b64': 'ICAgIGNhc2UgJ2Fuc3dlcic6CiAgICAgIHJldHVybiB7IHR5cGU6ICdhbnN3ZXInLCByZXBseTogc2MoZS5yZXBseSkgfTs=', 'guard': 'reply: sc(e.reply)'},
    {'file': 'src/agent/displayFirewall.js', 'anchor_b64': 'ICAgICAgZm9yIChjb25zdCBrIG9mIE9iamVjdC5rZXlzKGUpKSBzYWZlW2tdID0gdHlwZW9mIGVba10gPT09ICdzdHJpbmcnID8gc2NydWIoZVtrXSkgOiBlW2tdOw==', 'repl_b64': 'ICAgICAgZm9yIChjb25zdCBrIG9mIE9iamVjdC5rZXlzKGUpKSBzYWZlW2tdID0gdHlwZW9mIGVba10gPT09ICdzdHJpbmcnID8gc2MoZVtrXSkgOiBlW2tdOw==', 'guard': '? sc(e[k]) :'},
    {'file': 'src/api/vendor/chat.js', 'anchor_b64': 'Y29uc3QgeyB0cmFuc2xhdGVCZWF0LCBzYWZlU3RlcEtpbmRzIH0gPSByZXF1aXJlKCcuLi8uLi9hZ2VudC9kaXNwbGF5RmlyZXdhbGwnKTs=', 'repl_b64': 'Y29uc3QgeyB0cmFuc2xhdGVCZWF0LCBzYWZlU3RlcEtpbmRzIH0gPSByZXF1aXJlKCcuLi8uLi9hZ2VudC9kaXNwbGF5RmlyZXdhbGwnKTsKY29uc3QgeyBydW5NYW5hZ2VyVHVybiB9ID0gcmVxdWlyZSgnLi4vLi4vYWdlbnQvbWFuYWdlckxvb3AnKTs=', 'guard': "require('../../agent/managerLoop')"},
    {'file': 'src/api/vendor/chat.js', 'anchor_b64': 'ICBjb25zdCBhaVByaW1lciA9IHR5cGVvZiBib2R5LmFpX3ByaW1lciA9PT0gJ3N0cmluZycgPyBib2R5LmFpX3ByaW1lci50cmltKCkgOiAnJzs=', 'repl_b64': '', 'guard': "const runTurn = (mode === 'manager')"},
    {'file': 'src/api/vendor/chat.js', 'anchor_b64': 'ICAgICAgcmVzdWx0ID0gYXdhaXQgcnVuTXlyYVR1cm4oew==', 'repl_b64': 'ICAgICAgcmVzdWx0ID0gYXdhaXQgcnVuVHVybih7ICAvLyBtb2RlLXJvdXRlZCAoc3RyZWFtKQ==', 'guard': 'mode-routed (stream)'},
    {'file': 'src/api/vendor/chat.js', 'anchor_b64': 'ICAgICAgICAgIGNvbnN0IHNhZmUgPSB0cmFuc2xhdGVCZWF0KGUpOw==', 'repl_b64': 'ICAgICAgICAgIGNvbnN0IHNhZmUgPSB0cmFuc2xhdGVCZWF0KGUsIG1vZGUpOw==', 'guard': 'translateBeat(e, mode)'},
    {'file': 'src/api/vendor/chat.js', 'anchor_b64': 'ICAgIHJlc3VsdCA9IGF3YWl0IHJ1blBXQUFnZW50aWNUdXJuKHs=', 'repl_b64': 'ICAgIHJlc3VsdCA9IGF3YWl0IHJ1blR1cm4oeyAgLy8gbW9kZS1yb3V0ZWQgKGpzb24p', 'guard': 'mode-routed (json)'}
]

def apply_edit(e):
    path = e['file']
    if not os.path.exists(path):
        print("[ERROR] %s not found. Run from the dream-os repo root." % path); return False
    with open(path, "r", encoding="utf-8") as f:
        content = f.read()
    guard = e['guard']
    if guard and guard in content:
        print("[SKIP] %s already has %r — edit already applied." % (path, guard)); return True
    anchor = base64.b64decode(e['anchor_b64']).decode("utf-8")
    repl   = base64.b64decode(e['repl_b64']).decode("utf-8")
    n = content.count(anchor)
    if n != 1:
        print("[ERROR] anchor in %s found %d time(s) (expected 1). File UNTOUCHED. Anchor head: %r" % (path, n, anchor[:60])); return False
    content = content.replace(anchor, repl)
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print("[OK] patched %s (%r)" % (path, guard or anchor[:40]))
    return True

def main():
    ok = True
    if os.path.exists(NEW_FILE):
        with open(NEW_FILE, "r", encoding="utf-8") as f:
            existing = f.read()
        if "runManagerTurn" in existing:
            print("[SKIP] %s already exists with runManagerTurn." % NEW_FILE)
        else:
            print("[ERROR] %s exists but lacks runManagerTurn — refusing to overwrite." % NEW_FILE); ok = False
    else:
        os.makedirs(os.path.dirname(NEW_FILE), exist_ok=True)
        with open(NEW_FILE, "w", encoding="utf-8") as f:
            f.write(base64.b64decode(ML_B64).decode("utf-8"))
        print("[OK] created %s" % NEW_FILE)
    for e in EDITS:
        if not apply_edit(e):
            ok = False
    print("")
    if ok:
        print("[DONE] M2 applied. Gate before push:")
        print("       node --check src/agent/managerLoop.js")
        print("       node --check src/agent/displayFirewall.js")
        print("       node --check src/api/vendor/chat.js")
    else:
        print("[INCOMPLETE] a step did not apply — read the messages above; nothing partial was forced.")
        sys.exit(1)

if __name__ == "__main__":
    main()
